"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { 
  ArrowLeft, UserPlus, Users, Award, Shield, IndianRupee, 
  CheckCircle2, Eye, EyeOff, Mail, Lock, LogOut, 
  MapPin, Calendar, Building, Sparkles, AlertCircle, FileBadge 
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import ScrollReveal from "@/components/shared/ScrollReveal";
import { supabase } from "@/lib/supabaseClient";

type RoleType = "learner" | "teacher" | "mentor" | "organizer" | "donor";
type ViewMode = "login" | "register" | "forgot" | "reset";

export default function VolunteerPage() {
  const [viewMode, setViewMode] = useState<ViewMode>("login");
  const [userSession, setUserSession] = useState<any>(null);
  const [profileData, setProfileData] = useState<any>(null);

  // Tab control for registration
  const [activeTab, setActiveTab] = useState<RoleType>("learner");
  const [submittedId, setSubmittedId] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [countdown, setCountdown] = useState(5);

  // Login states
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [showLoginPassword, setShowLoginPassword] = useState(false);

  // Forgot password state
  const [forgotEmail, setForgotEmail] = useState("");

  // Reset password states
  const [newPassword, setNewPassword] = useState("");
  const [showNewPassword, setShowNewPassword] = useState(false);

  // Registration password toggles
  const [showRegPassword, setShowRegPassword] = useState(false);
  const [showRegConfirmPassword, setShowRegConfirmPassword] = useState(false);

  // Shared state for forms
  const [formData, setFormData] = useState({
    constituency: "",
    representative: "",
    name: "",
    age: "",
    gender: "M",
    guardian: "",
    motherTongue: "ಕನ್ನಡ",
    nativePlace: "",
    occupation: "",
    school: "",
    details: "",
    email: "",
    password: "",
    confirmPassword: "",
    linkedId1: "",
    linkedId2: "",
    linkedId3: "",
  });

  // Check auth session and reset flows on mount
  useEffect(() => {
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      if (session) {
        setUserSession(session);
        fetchUserProfile(session.user.id);
      }
    });

    // Check query params for password reset trigger
    const query = new URLSearchParams(window.location.search);
    if (query.get("reset") === "true" || window.location.hash.includes("type=recovery")) {
      setViewMode("reset");
    }
  }, []);

  // Monitor auth changes
  useEffect(() => {
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session) {
        setUserSession(session);
        fetchUserProfile(session.user.id);
      } else {
        setUserSession(null);
        setProfileData(null);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  // Fetch full volunteer details
  const fetchUserProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from("user_roles")
        .select("*")
        .eq("id", userId)
        .single();
      if (!error && data) {
        setProfileData(data);
      }
    } catch (err) {
      console.error("Error fetching user profile:", err);
    }
  };

  // 5 seconds redirect countdown handler
  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (submittedId && viewMode === "register") {
      setCountdown(5);
      interval = setInterval(() => {
        setCountdown((prev) => {
          if (prev <= 1) {
            clearInterval(interval);
            setViewMode("login");
            resetForm();
            return 5;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => {
      if (interval) clearInterval(interval);
    };
  }, [submittedId, viewMode]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData({
      constituency: "",
      representative: "",
      name: "",
      age: "",
      gender: "M",
      guardian: "",
      motherTongue: "ಕನ್ನಡ",
      nativePlace: "",
      occupation: "",
      school: "",
      details: "",
      email: "",
      password: "",
      confirmPassword: "",
      linkedId1: "",
      linkedId2: "",
      linkedId3: "",
    });
    setSubmittedId(null);
    setError(null);
    setSuccessMsg(null);
    setIsSubmitting(false);
  };

  // Login handler
  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);
    try {
      const { data, error: loginError } = await supabase.auth.signInWithPassword({
        email: loginEmail,
        password: loginPassword,
      });

      if (loginError) throw loginError;

      // Fetch role
      const { data: roleData } = await supabase
        .from("user_roles")
        .select("role")
        .eq("id", data.user.id)
        .single();

      if (roleData?.role === "admin") {
        window.location.href = "/volunteer/admin";
      } else {
        setSuccessMsg("ಲಾಗಿನ್ ಯಶಸ್ವಿಯಾಗಿದೆ!");
        fetchUserProfile(data.user.id);
      }
    } catch (err: any) {
      setError(err.message || "ಲಾಗಿನ್ ವಿಫಲವಾಗಿದೆ. ಇಮೇಲ್ ಅಥವಾ ಪಾಸ್‌ವರ್ಡ್ ಪರಿಶೀಲಿಸಿ.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Forgot Password handler
  const handleForgotPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);
    try {
      const { error: resetError } = await supabase.auth.resetPasswordForEmail(forgotEmail, {
        redirectTo: `${window.location.origin}/volunteer?reset=true`,
      });
      if (resetError) throw resetError;
      setSuccessMsg("ಪಾಸ್‌ವರ್ಡ್ ಮರುಹೊಂದಿಸುವ ಲಿಂಕ್ ಅನ್ನು ನಿಮ್ಮ ಇಮೇಲ್‌ಗೆ ಕಳುಹಿಸಲಾಗಿದೆ!");
    } catch (err: any) {
      setError(err.message || "ಇಮೇಲ್ ಕಳುಹಿಸಲು ಸಾಧ್ಯವಾಗಲಿಲ್ಲ.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Reset Password (new password submission) handler
  const handleResetPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);
    try {
      const { error: updateError } = await supabase.auth.updateUser({
        password: newPassword,
      });
      if (updateError) throw updateError;
      setSuccessMsg("ನಿಮ್ಮ ಪಾಸ್‌ವರ್ಡ್ ಯಶಸ್ವಿಯಾಗಿ ಅಪ್‌ಡೇಟ್ ಆಗಿದೆ! ದಯವಿಟ್ಟು ಲಾಗಿನ್ ಮಾಡಿ.");
      setTimeout(() => {
        setViewMode("login");
        window.history.replaceState({}, document.title, window.location.pathname);
      }, 3000);
    } catch (err: any) {
      setError(err.message || "ಪಾಸ್‌ವರ್ಡ್ ನವೀಕರಿಸಲು ಸಾಧ್ಯವಾಗಲಿಲ್ಲ.");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Registration handler
  const handleRegisterSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccessMsg(null);

    if (formData.password !== formData.confirmPassword) {
      setError("ಪಾಸ್‌ವರ್ಡ್‌ಗಳು ಹೊಂದಾಣಿಕೆಯಾಗುತ್ತಿಲ್ಲ.");
      setIsSubmitting(false);
      return;
    }

    if (formData.password.length < 6) {
      setError("ಪಾಸ್‌ವರ್ಡ್ ಕನಿಷ್ಠ ೬ ಅಕ್ಷರಗಳನ್ನು ಹೊಂದಿರಬೇಕು.");
      setIsSubmitting(false);
      return;
    }

    // Generate Custom display ID
    const prefixMap: Record<RoleType, string> = {
      learner: "LRN",
      teacher: "TCH",
      mentor: "MNT",
      organizer: "ORG",
      donor: "DNR",
    };
    const randNum = Math.floor(1000 + Math.random() * 9000);
    const generatedId = `KB-2026-${prefixMap[activeTab]}-${randNum}`;

    try {
      // 1. Create auth user
      const { data: signUpData, error: signUpError } = await supabase.auth.signUp({
        email: formData.email,
        password: formData.password,
      });

      if (signUpError) throw signUpError;
      if (!signUpData.user) throw new Error("ಖಾತೆ ರಚಿಸಲು ಸಾಧ್ಯವಾಗಲಿಲ್ಲ.");

      // 2. Upsert candidate details into user_roles
      let payload: Record<string, any> = {
        id: signUpData.user.id,
        registration_id: generatedId,
        role: activeTab,
        name: formData.name,
        age: parseInt(formData.age) || 0,
        gender: formData.gender,
        guardian: formData.guardian,
        constituency: formData.constituency,
        representative: formData.representative,
        email: formData.email
      };

      if (activeTab === "learner") {
        payload.mother_tongue = formData.motherTongue;
        payload.native_place = formData.nativePlace;
        payload.occupation = formData.occupation || null;
      } else if (activeTab === "teacher") {
        payload.school = formData.school;
        payload.linked_id_1 = formData.linkedId1;
      } else if (activeTab === "mentor") {
        payload.occupation = formData.occupation;
        payload.linked_id_1 = formData.linkedId1;
      } else if (activeTab === "organizer") {
        payload.occupation = formData.occupation;
        payload.linked_id_1 = formData.linkedId1;
      } else if (activeTab === "donor") {
        payload.school = formData.school;
        payload.linked_id_1 = formData.linkedId1;
      }

      // Upsert overwrites the row that the trigger automatically inserted
      const { error: upsertError } = await supabase.from("user_roles").upsert(payload);

      if (upsertError) throw upsertError;

      setSubmittedId(generatedId);
    } catch (err: any) {
      console.error("Registration error:", err);
      setError("ನೋಂದಣಿ ವೈಫಲ್ಯ: " + (err.message || "ದಯವಿಟ್ಟು ಸಂಪರ್ಕ ಸಾಧನಗಳನ್ನು ಪರಿಶೀಲಿಸಿ."));
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUserSession(null);
    setProfileData(null);
    setViewMode("login");
    resetForm();
  };

  return (
    <div className="container mx-auto px-4 sm:px-6 lg:px-8 max-w-4xl py-12">
      {/* Back button */}
      <Link href="/" className="inline-flex items-center gap-2 text-sm font-bold text-gray-500 hover:text-[#ED1C24] mb-8 transition-colors">
        <span className="notranslate flex-shrink-0 flex items-center justify-center" translate="no">
          <ArrowLeft className="w-4 h-4" />
        </span>
        <span>ಮುಖಪುಟಕ್ಕೆ ಮರಳಿ</span>
      </Link>

      {/* RENDER CANDIDATE DASHBOARD IF LOGGED IN */}
      {userSession && profileData ? (
        <ScrollReveal>
          <div className="glass rounded-3xl border border-white/60 shadow-xl p-6 sm:p-10 relative overflow-hidden">
            {/* Glow backgrounds */}
            <div className="absolute -right-20 -bottom-20 w-44 h-44 rounded-full bg-[#FFC20E]/5 blur-3xl pointer-events-none" />
            <div className="absolute -left-20 -top-20 w-44 h-44 rounded-full bg-[#ED1C24]/5 blur-3xl pointer-events-none" />

            {/* Dashboard Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center border-b border-amber-100/50 pb-6 mb-8 gap-4 relative z-10">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-gradient-to-br from-[#ED1C24] to-[#FFC20E] rounded-2xl flex items-center justify-center text-white font-extrabold text-xl shadow-md">
                  ಕ
                </div>
                <div>
                  <h1 className="text-xl sm:text-2xl font-heading font-extrabold text-gray-800">
                    ಶರಣು ಶರಣಾರ್ಥಿ, {profileData.name}!
                  </h1>
                  <span className="text-xs font-bold text-[#ED1C24] dark:text-[#FFC20E] uppercase tracking-wider block mt-1">
                    ಕನ್ನಡ ಭಾರತಿ ಸಕ್ರಿಯ ಸದಸ್ಯರು
                  </span>
                </div>
              </div>

              <Button 
                onClick={handleLogout}
                variant="outline" 
                className="border border-red-200 text-red-500 hover:bg-red-50 hover:text-red-600 rounded-full px-5 py-2.5 text-xs font-bold flex items-center gap-1.5 transition-all shadow-sm"
              >
                <LogOut className="w-4 h-4" />
                ಲೋಗೌಟ್
              </Button>
            </div>

            {/* Content Details Grid */}
            <div className="grid md:grid-cols-3 gap-6 relative z-10 mb-8">
              {/* Profile Card */}
              <div className="md:col-span-2 space-y-6">
                <div className="bg-amber-50/20 rounded-2xl border border-amber-100/60 p-6 space-y-4">
                  <h3 className="text-xs font-extrabold text-gray-400 uppercase tracking-widest border-b border-amber-100 pb-2">
                    ವೈಯಕ್ತಿಕ ಮಾಹಿತಿ (Profile Details)
                  </h3>

                  <div className="grid grid-cols-2 gap-x-4 gap-y-3.5 text-sm font-semibold">
                    <div>
                      <span className="text-xs text-gray-400 block">ಕ್ಷೇತ್ರ (Constituency)</span>
                      <span className="text-gray-700 flex items-center gap-1 mt-0.5">
                        <MapPin className="w-3.5 h-3.5 text-[#ED1C24]" />
                        {profileData.constituency || "ಬೆಂಗಳೂರು"}
                      </span>
                    </div>
                    <div>
                      <span className="text-xs text-gray-400 block">ಪ್ರತಿನಿಧಿ (Representative)</span>
                      <span className="text-gray-700 block mt-0.5">{profileData.representative || "ಮಹೇಶ್ ಗೌಡ"}</span>
                    </div>
                    <div>
                      <span className="text-xs text-gray-400 block">ವಯಸ್ಸು (Age)</span>
                      <span className="text-gray-700 flex items-center gap-1 mt-0.5">
                        <Calendar className="w-3.5 h-3.5 text-[#FFC20E]" />
                        {profileData.age} ವರ್ಷಗಳು
                      </span>
                    </div>
                    <div>
                      <span className="text-xs text-gray-400 block">ಲಿಂಗ (Gender)</span>
                      <span className="text-gray-700 block mt-0.5">
                        {profileData.gender === "M" ? "ಪುರುಷ" : profileData.gender === "F" ? "ಮಹಿಳೆ" : "ಇತರ"}
                      </span>
                    </div>
                    <div>
                      <span className="text-xs text-gray-400 block">ತಾಯಿ / ತಂದೆ ಪೋಷಕರು</span>
                      <span className="text-gray-700 block mt-0.5">{profileData.guardian}</span>
                    </div>
                    <div>
                      <span className="text-xs text-gray-400 block">ಇಮೇಲ್ (Email)</span>
                      <span className="text-gray-700 block mt-0.5 text-xs truncate">{profileData.email}</span>
                    </div>

                    {profileData.role === "learner" && (
                      <>
                        <div>
                          <span className="text-xs text-gray-400 block">ಮಾತೃ ಭಾಷೆ</span>
                          <span className="text-gray-700 block mt-0.5">{profileData.mother_tongue}</span>
                        </div>
                        <div>
                          <span className="text-xs text-gray-400 block">ಮೂಲ ಸ್ಥಳ</span>
                          <span className="text-gray-700 block mt-0.5">{profileData.native_place}</span>
                        </div>
                        <div className="col-span-2">
                          <span className="text-xs text-gray-400 block">ವೃತ್ತಿ</span>
                          <span className="text-gray-700 block mt-0.5">{profileData.occupation || "ಲಭ್ಯವಿಲ್ಲ"}</span>
                        </div>
                      </>
                    )}

                    {profileData.role !== "learner" && (
                      <>
                        <div className="col-span-2">
                          <span className="text-xs text-gray-400 block">
                            {profileData.role === "donor" ? "ಸಂಸ್ಥೆ / ಟ್ರಸ್ಟ್" : "ಓದುತ್ತಿರುವ ಶಾಲೆ / ತರಗತಿ / ವೃತ್ತಿ"}
                          </span>
                          <span className="text-gray-700 flex items-center gap-1 mt-0.5">
                            <Building className="w-3.5 h-3.5 text-amber-500" />
                            {profileData.school || profileData.occupation || "ಲಭ್ಯವಿಲ್ಲ"}
                          </span>
                        </div>
                        <div className="col-span-2">
                          <span className="text-xs text-gray-400 block">ಲಿಂಕ್ ಮಾಡಲಾದ ಐಡಿ ಸಂಖ್ಯೆ</span>
                          <span className="font-extrabold text-[#ED1C24] block mt-0.5">{profileData.linked_id_1}</span>
                        </div>
                      </>
                    )}
                  </div>
                </div>

                {profileData.details && (
                  <div className="bg-gray-50/50 rounded-2xl border border-gray-100 p-6 space-y-2">
                    <span className="text-xs text-gray-400 font-bold block">ವೈಯಕ್ತಿಕ ಹಿನ್ನೆಲೆ ವಿವರ</span>
                    <p className="text-gray-600 text-xs sm:text-sm font-semibold leading-relaxed">
                      {profileData.details}
                    </p>
                  </div>
                )}
              </div>

              {/* Status / Role Card */}
              <div className="space-y-6">
                <div className="bg-gradient-to-br from-[#ED1C24] to-[#D11820] text-white rounded-2xl p-6 shadow-md shadow-[#ED1C24]/10 space-y-4">
                  <div className="flex justify-between items-center border-b border-white/20 pb-2">
                    <span className="text-[10px] font-bold uppercase tracking-wider">ನೋಂದಣಿ ಐಡಿ</span>
                    <FileBadge className="w-5 h-5 text-[#FFC20E]" />
                  </div>

                  <div className="space-y-1">
                    <span className="text-2xl font-black block tracking-tight">
                      {profileData.registration_id || "KB-USER-PENDING"}
                    </span>
                    <span className="text-xs font-extrabold text-[#FFC20E] uppercase tracking-widest block">
                      {profileData.role === "learner" && "ಕಲಿಯುವವರು (Form 1)"}
                      {profileData.role === "teacher" && "ಕಲಿಸುವ ಮಕ್ಕಳು (Form 2)"}
                      {profileData.role === "mentor" && "ಮಾರ್ಗದರ್ಶಕರು (Form 3)"}
                      {profileData.role === "organizer" && "ಸಂಘಟಕರು (Form 4)"}
                      {profileData.role === "donor" && "ದಾನಿಗಳು (Form 5)"}
                    </span>
                  </div>

                  <p className="text-[11px] font-semibold text-white/80 leading-relaxed pt-2">
                    ನಾಡಿನ ಪ್ರತಿಯೊಬ್ಬರಿಗೂ ಕನ್ನಡ ಓದುವುದು, ಬರೆಯುವುದು ಕಲಿಸುವ ಈ ಮಹಾನ್ ಅಭಿಯಾನಕ್ಕೆ ಕೈಜೋಡಿಸಿದ್ದಕ್ಕಾಗಿ ಧನ್ಯವಾದಗಳು.
                  </p>
                </div>

                {/* Helpful guides based on roles */}
                <div className="bg-white/60 backdrop-blur-sm border border-amber-100 rounded-2xl p-6 space-y-3 shadow-inner">
                  <div className="flex items-center gap-1.5 text-xs font-bold text-amber-600">
                    <Sparkles className="w-4 h-4 text-[#FFC20E]" />
                    <span>ಮುಂದಿನ ಹಂತಗಳು (Next Steps)</span>
                  </div>
                  <ul className="space-y-2 text-xs font-semibold text-gray-500 list-disc list-inside">
                    {profileData.role === "learner" && (
                      <>
                        <li>ನಿಮ್ಮ ನಿಯೋಜಿತ ಶಿಕ್ಷಕರನ್ನು ಸಂಪರ್ಕಿಸಿ.</li>
                        <li>ಕನ್ನಡ ವರ್ಣಮಾಲೆ ಕಲಿಯಲು ಸಿದ್ಧರಾಗಿ.</li>
                        <li>ಕನ್ನಡ ಪುಸ್ತಕಗಳನ್ನು ನಿಯಮಿತವಾಗಿ ಓದಿ.</li>
                      </>
                    )}
                    {profileData.role === "teacher" && (
                      <>
                        <li>ಕನಿಷ್ಠ ೧೦ ಜನರಿಗೆ ಕನ್ನಡ ಕಲಿಸಿರಿ.</li>
                        <li>ನಿಮ್ಮ ವಿದ್ಯಾರ್ಥಿಗಳ ಪ್ರಗತಿ ದಾಖಲಿಸಿ.</li>
                        <li>ಮಾರ್ಗದರ್ಶಕರ ಸಹಾಯ ಪಡೆದುಕೊಳ್ಳಿ.</li>
                      </>
                    )}
                    {profileData.role === "mentor" && (
                      <>
                        <li>ನಿಮ್ಮ ಅಧೀನದ ಶಿಕ್ಷಕರನ್ನು ಭೇಟಿ ಮಾಡಿ.</li>
                        <li>ಕಲಿಕಾ ಸಂಪನ್ಮೂಲಗಳನ್ನು ಹಂಚಿರಿ.</li>
                        <li>ಆಯಾ ಕ್ಷೇತ್ರದ ಪ್ರಗತಿಯನ್ನು ಮೇಲ್ವಿಚಾರಣೆ ಮಾಡಿ.</li>
                      </>
                    )}
                    {profileData.role === "organizer" && (
                      <>
